/**
 * Core type definitions for the Panaudia MOQ client
 *
 * These types align with the MOQ Transport specification (draft-ietf-moq-transport-11)
 * and the Panaudia spatial mixer data structures.
 */

// ============================================================================
// Spatial Audio Types
// ============================================================================

/**
 * 3D position in Panaudia internal coordinates (0 to 1 range)
 */
export interface Position {
  x: number;
  y: number;
  z: number;
}

/**
 * 3D rotation in degrees
 */
export interface Rotation {
  yaw: number;
  pitch: number;
  roll: number;
}

/**
 * NodeInfo3 state data - matches the 48-byte binary format from Go server
 */
export interface NodeInfo3 {
  uuid: string;
  position: Position;
  rotation: Rotation;
  volume: number;
  gone: boolean;
}

// ============================================================================
// MOQ Transport Types
// ============================================================================

/**
 * MOQ message types (from draft-ietf-moq-transport-11)
 */
export enum MoqMessageType {
  // Session Messages
  CLIENT_SETUP = 0x40,
  SERVER_SETUP = 0x41,

  // Announcement Messages
  ANNOUNCE = 0x06,
  ANNOUNCE_OK = 0x07,
  ANNOUNCE_ERROR = 0x08,
  UNANNOUNCE = 0x09,

  // Subscription Messages
  SUBSCRIBE = 0x03,
  SUBSCRIBE_OK = 0x04,
  SUBSCRIBE_ERROR = 0x05,
  UNSUBSCRIBE = 0x0a,
  SUBSCRIBE_DONE = 0x0b,

  // Object Messages
  OBJECT_STREAM = 0x00,
  OBJECT_DATAGRAM = 0x01,

  // Other
  GOAWAY = 0x10,
}

/**
 * MOQ Setup parameters
 */
export enum MoqSetupParameter {
  ROLE = 0x00,
  PATH = 0x01,
  MAX_SUBSCRIBE_ID = 0x02,
}

/**
 * MOQ role values
 */
export enum MoqRole {
  PUBLISHER = 0x00,
  SUBSCRIBER = 0x01,
  PUBSUB = 0x02,
}

/**
 * MOQ filter type for subscriptions
 */
export enum MoqFilterType {
  LATEST_GROUP = 0x01,
  LATEST_OBJECT = 0x02,
  ABSOLUTE_START = 0x03,
  ABSOLUTE_RANGE = 0x04,
}

/**
 * MOQ object forwarding preference
 */
export enum MoqForwardingPreference {
  DATAGRAM = 0x00,
  STREAM_TRACK = 0x01,
  STREAM_GROUP = 0x02,
  STREAM_OBJECT = 0x03,
}

/**
 * MOQ error codes
 */
export enum MoqErrorCode {
  NO_ERROR = 0x00,
  INTERNAL_ERROR = 0x01,
  UNAUTHORIZED = 0x02,
  PROTOCOL_VIOLATION = 0x03,
  DUPLICATE_TRACK_ALIAS = 0x04,
  PARAMETER_LENGTH_MISMATCH = 0x05,
  TOO_MANY_SUBSCRIBES = 0x06,
  GOAWAY_TIMEOUT = 0x10,

  // Custom error codes
  INVALID_TOKEN = 0x403,
}

/**
 * MOQ Track representation
 */
export interface MoqTrack {
  namespace: string[];
  name: string;
  alias?: number;
}

/**
 * MOQ Object representation
 */
export interface MoqObject {
  trackAlias: number;
  groupId: bigint;
  objectId: bigint;
  publisherPriority: number;
  payload: Uint8Array;
}

/**
 * MOQ Subscription request
 */
export interface MoqSubscription {
  subscribeId: number;
  trackAlias: number;
  namespace: string[];
  trackName: string;
  filterType: MoqFilterType;
  authorization?: string;
}

/**
 * MOQ Announcement
 */
export interface MoqAnnouncement {
  namespace: string[];
  parameters?: Map<number, Uint8Array>;
}

// ============================================================================
// Client Configuration Types
// ============================================================================

/**
 * Configuration for the Panaudia MOQ client
 */
export interface PanaudiaConfig {
  /** Server URL (e.g., "https://server.example.com:4433") */
  serverUrl: string;

  /** JWT authentication token */
  ticket: string;

  /** Node ID (UUID) - typically extracted from JWT, but can be provided */
  nodeId?: string;

  /** Initial position in Panaudia coordinates (0-1 range) */
  initialPosition?: Position;

  /** Initial rotation in degrees */
  initialRotation?: Rotation;

  /** Initial volume (0-1 range) */
  initialVolume?: number;
}

/**
 * Connection state
 */
export enum ConnectionState {
  DISCONNECTED = 'disconnected',
  CONNECTING = 'connecting',
  CONNECTED = 'connected',
  AUTHENTICATED = 'authenticated',
  ERROR = 'error',
}

/**
 * Client event types
 */
export type ClientEventType =
  | 'connected'
  | 'disconnected'
  | 'authenticated'
  | 'error'
  | 'statechange';

/**
 * Client event handler
 */
export type ClientEventHandler<T = unknown> = (event: T) => void;

/**
 * Error event payload
 */
export interface ErrorEvent {
  code: string | number;
  message: string;
  details?: unknown;
}

/**
 * State change event payload
 */
export interface StateChangeEvent {
  previousState: ConnectionState;
  currentState: ConnectionState;
}

// ============================================================================
// Track Types (Panaudia-specific)
// ============================================================================

/**
 * Track types used by Panaudia
 */
export enum PanaudiaTrackType {
  AUDIO_INPUT = 'in/audio/opus-mono',
  AUDIO_OUTPUT = 'out/audio/opus-stereo',
  STATE = 'state',
}

/**
 * Generate track namespace for Panaudia
 */
export function generateTrackNamespace(trackType: PanaudiaTrackType, nodeId: string): string[] {
  switch (trackType) {
    case PanaudiaTrackType.AUDIO_INPUT:
      return ['in', 'audio', 'opus-mono', nodeId];
    case PanaudiaTrackType.AUDIO_OUTPUT:
      return ['out', 'audio', 'opus-stereo', nodeId];
    case PanaudiaTrackType.STATE:
      return ['state', nodeId];
    default:
      throw new Error(`Unknown track type: ${trackType}`);
  }
}

// ============================================================================
// WebTransport Types (browser API supplements)
// ============================================================================

/**
 * WebTransport hash for server certificate verification
 */
export interface WebTransportHash {
  algorithm: string;
  value: BufferSource;
}

/**
 * WebTransport connection options
 */
export interface WebTransportOptions {
  /** Server certificate hashes for self-signed certs (development) */
  serverCertificateHashes?: WebTransportHash[];

  /** Allow pooling with other connections */
  allowPooling?: boolean;

  /** Require unreliable transport (datagrams) */
  requireUnreliable?: boolean;

  /** Congestion control algorithm */
  congestionControl?: 'default' | 'throughput' | 'low-latency';
}
